CREATE TABLE clinics (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name VARCHAR(255) NOT NULL, address TEXT, phone VARCHAR(20), email VARCHAR(255), registration_number VARCHAR(100) UNIQUE, plan VARCHAR(50) DEFAULT 'free', status VARCHAR(50) DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, created_by VARCHAR(255));
CREATE TABLE doctors (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), clinic_id UUID NOT NULL REFERENCES clinics(id) ON DELETE CASCADE, name VARCHAR(255) NOT NULL, email VARCHAR(255), phone VARCHAR(20), specialization VARCHAR(255), license_number VARCHAR(100), qualifications TEXT, status VARCHAR(50) DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE(clinic_id, license_number));
CREATE TABLE patients (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), clinic_id UUID NOT NULL REFERENCES clinics(id) ON DELETE CASCADE, first_name VARCHAR(255) NOT NULL, last_name VARCHAR(255) NOT NULL, date_of_birth DATE, gender VARCHAR(10), email VARCHAR(255), phone VARCHAR(20), address TEXT, emergency_contact VARCHAR(255), emergency_phone VARCHAR(20), medical_history TEXT, allergies TEXT, status VARCHAR(50) DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE(clinic_id, email));
CREATE TABLE appointments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), clinic_id UUID NOT NULL REFERENCES clinics(id) ON DELETE CASCADE, doctor_id UUID NOT NULL REFERENCES doctors(id) ON DELETE RESTRICT, patient_id UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE, appointment_date TIMESTAMP NOT NULL, duration_minutes INT DEFAULT 30, reason TEXT, notes TEXT, status VARCHAR(50) DEFAULT 'scheduled', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE medical_records (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), clinic_id UUID NOT NULL REFERENCES clinics(id) ON DELETE CASCADE, patient_id UUID NOT NULL REFERENCES patients(id) ON DELETE CASCADE, appointment_id UUID REFERENCES appointments(id) ON DELETE SET NULL, doctor_id UUID NOT NULL REFERENCES doctors(id) ON DELETE RESTRICT, record_type VARCHAR(100), title VARCHAR(255), content TEXT NOT NULL, attachments JSONB, visibility VARCHAR(50) DEFAULT 'private', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, created_by UUID);
CREATE TABLE clinic_users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), clinic_id UUID NOT NULL REFERENCES clinics(id) ON DELETE CASCADE, email VARCHAR(255) NOT NULL, password_hash VARCHAR(255) NOT NULL, full_name VARCHAR(255), role VARCHAR(50) DEFAULT 'doctor', status VARCHAR(50) DEFAULT 'active', last_login TIMESTAMP, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, UNIQUE(clinic_id, email));
CREATE TABLE audit_logs (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), clinic_id UUID NOT NULL REFERENCES clinics(id) ON DELETE CASCADE, user_id UUID REFERENCES clinic_users(id) ON DELETE SET NULL, action VARCHAR(255) NOT NULL, resource_type VARCHAR(100), resource_id UUID, changes JSONB, ip_address VARCHAR(45), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);